const projs = $input.first().json.projects || [];
const phases = ['intake','briefing_done','design_done','analysis_done','costs_done','trades_done','proposal_done','approved','planning_done','in_construction'];
const phaseLabel = { intake:'Intake', briefing_done:'Briefing', design_done:'Design', analysis_done:'Regulatorio', costs_done:'Costes', trades_done:'Trades', proposal_done:'Propuesta', approved:'Aprobado', planning_done:'Planning', in_construction:'En obra' };
const byPhase = {};
phases.forEach(p => byPhase[p] = []);
projs.forEach(p => { if (byPhase[p.current_phase]) byPhase[p.current_phase].push(p); });
const card = p => '<a href="/webhook/admin-project?project_id='+p.id+'" style="display:block;background:white;padding:10px 12px;border-radius:6px;text-decoration:none;color:#1f2937;margin-bottom:8px;border-left:3px solid '+(p.days_idle > 14 ? '#dc2626' : (p.days_idle > 7 ? '#f59e0b' : '#10b981'))+'"><div style="font-weight:600;font-size:13px">'+(p.name||'?')+'</div><div style="color:#6b7280;font-size:11px;margin-top:2px">'+(p.client_name||'?')+' • '+(p.location_city||'?')+'</div><div style="color:'+(p.days_idle > 7 ? '#dc2626' : '#9ca3af')+';font-size:11px;margin-top:2px">'+p.days_idle+'d sin actividad'+(p.budget_target ? ' • '+Number(p.budget_target).toLocaleString('es-ES')+' EUR' : '')+'</div></a>';
const column = phase => '<div style="flex:0 0 240px;background:#f9fafb;padding:12px;border-radius:8px;min-height:200px"><div style="font-size:11px;color:#6b7280;text-transform:uppercase;font-weight:600;margin-bottom:8px;letter-spacing:.5px">'+phaseLabel[phase]+' <span style="color:#9ca3af;font-weight:normal">('+byPhase[phase].length+')</span></div>'+(byPhase[phase].length>0 ? byPhase[phase].map(card).join('') : '<div style="color:#9ca3af;font-size:12px;font-style:italic">vacio</div>')+'</div>';
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Pipeline — ArquitAI</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:none;margin:24px;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 4px}.meta{color:#64748b;font-size:13px}.kanban{display:flex;gap:12px;overflow-x:auto;padding-bottom:12px;margin-top:16px}</style>' +
'</head><body>' +
'<a href="/webhook/admin-index" style="color:#2563eb;font-size:13px;text-decoration:none">← Admin index</a>' +
'<h1>Pipeline de proyectos</h1>' +
'<div class="meta">'+projs.length+' proyectos activos. Borde verde: <7d sin actividad. Naranja: 7-14d. Rojo: >14d. Click en un proyecto para abrir su drill-down.</div>' +
'<div class="kanban">' + phases.map(column).join('') + '</div>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:24px;text-align:center">Datos: projects.current_phase. Para mas detalle de un proyecto, click en su tarjeta.</p>' +
'</body></html>';
return [{ json: { html } }];
